// Runtime-agnostic WebGPU compat test #1: adapter + device acquisition.
// Runs under Deno (oracle) and monster (under test); the harness diffs the
// single `__RESULT__ <json>` line each emits. Compares shape/booleans, not
// opaque handle identities.
const out = {};
out.hasGpu = typeof navigator !== 'undefined' && !!navigator.gpu;
if (out.hasGpu) {
  const adapter = await navigator.gpu.requestAdapter();
  out.hasAdapter = !!adapter;
  if (adapter) {
    const device = await adapter.requestDevice();
    out.hasDevice = !!device;
    out.hasQueue = !!(device && device.queue);
  }
}
console.log('__RESULT__ ' + JSON.stringify(out));
